package testingModule;

public class TestingCode {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		System.out.println( (int)10.99 ); // a)
		System.out.println( 6 * 2 / 6 ); // b)
		System.out.println( 2 / 4 * 4 ); // c)
		System.out.println( 2.0 / 4 * 4 ); // d)
		System.out.println( 3 * 1.1 ); // e) Note: This does not print 3.3
		System.out.println( 1 > 2 ); // f
	}

}
